				&lt;Notice&gt;&lt;/Notice&gt;
				&lt;RelaToInsured&gt;01&lt;/RelaToInsured&gt;
			&lt;/Appl&gt;
			&lt;Bnfs&gt;
				&lt;Count&gt;1&lt;/Count&gt;
				&lt;Type1&gt;&lt;/Type1&gt;
				&lt;Name1&gt;&lt;/Name1&gt;
				&lt;Sex1&gt;&lt;/Sex1&gt;
